script:
frappe.ui.form.on("Book Issue", {

    refresh: function(frm) {
        if (frm.doc.issue_date && !frm.doc.due_date) {
            calculate_due_date(frm);
        }
    },

    issue_date: function(frm) {
        calculate_due_date(frm);
    },

    library_member: function(frm) {
        if (frm.doc.library_member) {
            frappe.db.get_value(
                "Library Member",
                frm.doc.library_member,
                "member_name",
                function(r) {
                    if (r && r.member_name) {
                        frm.set_value("member_name", r.member_name);
                    }
                }
            );
        }
    },

    library_book: function(frm) {

        if (!frm.doc.library_book) {
            frm.set_value("book_copy", "");
            return;
        }

        frappe.db.get_list("Book Copy", {
            filters: {
                library_book: frm.doc.library_book,
                copy_status: "Available"
            },
            fields: ["name"],
            limit: 1
        }).then(function(r) {

            if (r.length > 0) {

                frm.set_value("book_copy", r[0].name);

                frappe.show_alert({
                    message: "Available book copy assigned automatically.",
                    indicator: "green"
                });

            } else {

                frm.set_value("book_copy", "");

                frappe.msgprint({
                    title: "No Copies Available",
                    message: "All copies of this book are currently issued.",
                    indicator: "red"
                });

            }

        });

    }

});

function calculate_due_date(frm) {

    frappe.db.get_single_value("Library Settings", "issue_duration_days")
    .then(function(days) {

        var issue_days = days || 21;

        if (frm.doc.issue_date) {

            var due_date = frappe.datetime.add_days(frm.doc.issue_date, issue_days);

            frm.set_value("due_date", due_date);
            frm.set_value("issue_status", "Issued");

            frappe.show_alert({
                message: "Due date set to " + due_date + " (" + issue_days + " days)",
                indicator: "green"
            }, 4);

        }

    });

}
